/**
 * Header Scripts - Optimized for Mobile Navigation Logic
 * Fixes: Link navigation for leaf nodes & Initial '+' indicator
 */

(function () {
  'use strict';

  /* ========================================
   * UTILITIES
   * ======================================== */
  function debounce(func, wait) {
    let timeout;
    return function (...args) {
      clearTimeout(timeout);
      timeout = setTimeout(() => func.apply(this, args), wait);
    };
  }

  function isDesktop() {
    return window.innerWidth > 992; // Match CSS breakpoint
  }

  /* ========================================
   * MAIN INITIALIZATION
   * ======================================== */

  document.addEventListener('DOMContentLoaded', function () {

    const elements = {
      mobileToggle: document.querySelector('.mobile-menu-toggle'),
      mobileMenu: document.querySelector('.mobile-menu'),
      megamenuTrigger: document.querySelector('.nav-trigger'),
      megamenuNav: document.querySelector('.megamenu-categories'), 
      mobileMegamenuNav: document.querySelector('.mobile-products-list'),
      body: document.body
    };

    /* 1. Mobile Menu Toggle */
    if (elements.mobileToggle && elements.mobileMenu) {
      elements.mobileToggle.addEventListener('click', function () {
        const isExpanded = this.getAttribute('aria-expanded') === 'true';
        this.setAttribute('aria-expanded', !isExpanded);
        elements.mobileMenu.setAttribute('aria-hidden', isExpanded);
        elements.body.style.overflow = !isExpanded ? 'hidden' : '';
      });
    }

    /* 2. Main Submenu Toggle (Mobile - Level 1) */
    if (elements.mobileMenu) {
      elements.mobileMenu.addEventListener('click', function (e) {
        const toggle = e.target.closest('.submenu-toggle');
        if (!toggle) return;
        const parent = toggle.parentElement;
        parent.classList.toggle('active');
      });
    }

    /* 3. Desktop Megamenu Logic */
    if (elements.megamenuTrigger) {
      elements.megamenuTrigger.addEventListener('click', function () {
        const isExpanded = this.getAttribute('aria-expanded') === 'true';
        this.setAttribute('aria-expanded', !isExpanded);
      });
      document.addEventListener('click', function (e) {
        if (!e.target.closest('.has-megamenu')) {
          elements.megamenuTrigger.setAttribute('aria-expanded', 'false');
        }
      });
    }

    /* 4. Init Dynamic Menus */
    if (elements.megamenuNav) initDynamicMegamenu(elements.megamenuNav, true); // Desktop Mode
    if (elements.mobileMegamenuNav) initDynamicMegamenu(elements.mobileMegamenuNav, false); // Mobile Mode

    /* 5. Resize Handler */
    const handleResize = debounce(function () {
      if (isDesktop() && elements.mobileMenu && elements.mobileToggle) {
        elements.mobileToggle.setAttribute('aria-expanded', 'false');
        elements.mobileMenu.setAttribute('aria-hidden', 'true');
        elements.body.style.overflow = '';
      }
    }, 150);
    window.addEventListener('resize', handleResize);
  });

  /* ========================================
   * DYNAMIC MEGAMENU LOGIC (FIXED)
   * ======================================== */

  function initDynamicMegamenu(nav, isDesktopMode) {
    if (!nav) return;

    const dataEl = document.getElementById('cmenu-data');
    if (!dataEl) return;

    let tree;
    try {
      tree = JSON.parse(dataEl.textContent);
    } catch (e) {
      console.error('Invalid menu JSON');
      return;
    }

    // بررسی اولیه: اضافه کردن کلاس has-children به آیتم‌های ریشه در موبایل
    // این کار باعث می‌شود علامت + همان اول دیده شود
    if (!isDesktopMode) {
        const rootItems = nav.querySelectorAll('li[data-id]');
        rootItems.forEach(li => {
            const id = li.dataset.id;
            if (tree[id] && tree[id].length > 0) {
                li.classList.add('has-children'); // کلاس برای CSS
            }
        });
    }

    /**
     * Create Submenu Helper
     */
    function createSubmenu(children) {
      const subUl = document.createElement('ul');
      subUl.className = 'cmenu-submenu';
      const fragment = document.createDocumentFragment();

      children.forEach(item => {
        const subLi = document.createElement('li');
        subLi.className = 'cmenu-submenu-item ' + (item.type === 'category' ? 'cmenu-subcategory' : 'cmenu-product');
        
        // اگر این آیتم خودش فرزندانی دارد، کلاس has-children بدهیم
        if (tree[item.id] && tree[item.id].length > 0) {
            subLi.classList.add('has-children');
        }

        if (item.type === 'category') subLi.dataset.id = item.id;
        subLi.dataset.type = item.type;

        const a = document.createElement('a');
        a.href = item.url;
        a.textContent = item.name;

        subLi.appendChild(a);
        fragment.appendChild(subLi);
      });

      subUl.appendChild(fragment);
      return subUl;
    }

    /**
     * Open Submenu Logic
     */
    function openSubmenu(li) {
      if (li.dataset.opened === 'true') return;

      const itemId = li.dataset.id;
      const children = tree[itemId] || [];

      if (!children.length) return;

      // Add structural class
      li.classList.add('cmenu-has-submenu');
      if(children.length > 0) li.classList.add('has-children');

      const submenu = createSubmenu(children);
      li.appendChild(submenu);
      li.dataset.opened = 'true';
    }

    /* 
     * Desktop Interaction (Hover)
     */
    if (isDesktopMode) {
      nav.addEventListener('mouseover', function (e) {
        if (!isDesktop()) return;
        const li = e.target.closest('li[data-id]');
        if (!li) return;
        openSubmenu(li);
      });
    }

    /* 
  * Mobile Interaction (Click) - FIXED & FINAL LOGIC
  */
    if (!isDesktopMode) {
      nav.addEventListener('click', function (e) {
        if (isDesktop()) return;

        // 1. پیدا کردن li مربوطه (ممکن است محصول باشد یا دسته)
        // ما دنبال نزدیک‌ترین li هستیم که کلاس آیتم منو را دارد
        const li = e.target.closest('li.cmenu-subcategory, li.cmenu-product, li.has-submenu');

        // اگر کلیک خارج از آیتم‌های منو بود، کاری نداریم
        if (!li) return;

        // 2. پیدا کردن ID برای چک کردن فرزندان
        // اگر li فعلی ID نداشت (مثل محصولات)، یعنی قطعاً فرزند ندارد
        const itemId = li.dataset.id;

        // اگر ID نداشت (محصول است) یا در درخت فرزند نداشت:
        if (!itemId || !tree[itemId] || tree[itemId].length === 0) {
          // اجازه بده لینک کار کند (هیچ کاری نکن و خارج شو)
          return;
        }

        // 3. اگر به اینجا رسیدیم، یعنی آیتم کلیک شده "دارای زیرمنو" است.

        // حالا باید مطمئن شویم کاربر روی خود لینک یا فلش کلیک کرده تا منو باز شود
        // و جلوی رفتن به صفحه دسته بندی (اگر لینک دارد) را بگیریم تا منو باز شود
        e.preventDefault();
        e.stopPropagation();

        // اگر هنوز ساخته نشده، بساز
        if (li.dataset.opened !== 'true') {
          openSubmenu(li);
        }

        // باز و بسته کردن کلاس open
        li.classList.toggle('open');
      });
    }
  }

})();
